// Pre-Validate Dimensions — runs BEFORE the AI agent
// Annotates chatInput with computed validation results so AI doesn't need to do math

const VALID_028 = [];
for (let v = 1.12; v <= 30; v = Math.round((v + 0.28) * 100) / 100) {
  VALID_028.push(Math.round(v * 100) / 100);
}

function findNearest028(val) {
  let closest = VALID_028[0];
  let minDiff = Math.abs(val - closest);
  for (const v of VALID_028) {
    const d = Math.abs(val - v);
    if (d < minDiff) { minDiff = d; closest = v; }
  }
  return closest;
}

function isValidAltura(val) {
  if (val < 2.0 || val > 6.0) return false;
  const diff = Math.round((val - 2.0) * 100);
  return diff % 5 === 0;
}

function findNearestAltura(val) {
  const clamped = Math.min(6.0, Math.max(2.0, val));
  const diff = Math.round((clamped - 2.0) * 100);
  const lower = 2.0 + Math.floor(diff / 5) * 0.05;
  const upper = Math.min(6.0, lower + 0.05);
  return Math.abs(val - lower) <= Math.abs(val - upper) ? lower : upper;
}

// Parse allData from the chatInput or from item fields
let allData = {};
try {
  const raw = $input.first().json.chatInput || '';
  const match = raw.match(/Dados do Formulário \(allData\):\n(.+?)\n\nSchema/s);
  if (match) allData = JSON.parse(match[1]);
} catch(e) {}

// Also try from the original fields passed through
try {
  if (!allData.step3) {
    const items = $input.all();
    for (const item of items) {
      if (item.json.allData) {
        allData = typeof item.json.allData === 'string' ? JSON.parse(item.json.allData) : item.json.allData;
        break;
      }
    }
  }
} catch(e) {}

const step3 = allData.step3 || {};
const annotations = [];

// Validate comprimento
if (step3.comprimento) {
  const num = parseFloat(step3.comprimento);
  if (!isNaN(num)) {
    if (VALID_028.includes(Math.round(num * 100) / 100)) {
      annotations.push(`comprimento (${num}m): ✅ VÁLIDO — está na grade modular`);
    } else {
      const nearest = findNearest028(num);
      annotations.push(`comprimento (${num}m): ❌ NÃO MODULAR — valor válido mais próximo: ${nearest.toFixed(2)}m`);
    }
  }
}

// Validate largura
if (step3.largura) {
  const num = parseFloat(step3.largura);
  if (!isNaN(num)) {
    if (VALID_028.includes(Math.round(num * 100) / 100)) {
      annotations.push(`largura (${num}m): ✅ VÁLIDO — está na grade modular`);
    } else {
      const nearest = findNearest028(num);
      annotations.push(`largura (${num}m): ❌ NÃO MODULAR — valor válido mais próximo: ${nearest.toFixed(2)}m`);
    }
  }
}

// Validate altura
if (step3.altura) {
  const num = parseFloat(step3.altura);
  if (!isNaN(num)) {
    if (isValidAltura(num)) {
      annotations.push(`altura (${num}m): ✅ VÁLIDO — múltiplo de 0.05m`);
    } else {
      const nearest = findNearestAltura(num);
      annotations.push(`altura (${num}m): ❌ NÃO VÁLIDO — valor válido mais próximo: ${nearest.toFixed(2)}m`);
    }
  }
}

// Calculate area and luminarias check
const comp = parseFloat(step3.comprimento) || 0;
const larg = parseFloat(step3.largura) || 0;
if (comp > 0 && larg > 0) {
  const area = comp * larg;
  const lumRec = Math.max(1, Math.ceil(area / 6));
  const lumMax = Math.ceil(area / 3);
  annotations.push(`área calculada: ${area.toFixed(1)}m² (${comp}×${larg}) — luminárias recomendadas: ${lumRec}, máximo razoável: ${lumMax}`);

  const qtdLum = parseInt(step3.qtd_luminarias) || 0;
  if (qtdLum > 0) {
    if (qtdLum > lumMax) {
      annotations.push(`qtd_luminarias (${qtdLum}): ❌ EXCESSIVO para ${area.toFixed(1)}m² (máx ${lumMax})`);
    } else if (qtdLum < Math.max(1, Math.floor(area / 15))) {
      annotations.push(`qtd_luminarias (${qtdLum}): ⚠️ POUCO para ${area.toFixed(1)}m² (recomendado ${lumRec})`);
    } else {
      annotations.push(`qtd_luminarias (${qtdLum}): ✅ OK para ${area.toFixed(1)}m²`);
    }
  }
}

// Append annotations to chatInput
let chatInput = $input.first().json.chatInput || '';
if (annotations.length > 0) {
  chatInput += '\n\n[PRÉ-VALIDAÇÃO COMPUTACIONAL — RESULTADOS EXATOS, USE COMO VERDADE]:\n' + annotations.join('\n');
}

return [{ json: { chatInput, sessionId: $input.first().json.sessionId } }];

