// Tool: Validar Dimensão Modular
// Input: query string like "comprimento 21.00" or "largura 5.32" or "altura 3.50"

const input = $input.first().json.query || '';
const parts = input.trim().split(/\s+/);
const campo = parts[0] || 'comprimento';
const valor = parseFloat(parts[1] || parts[0]);

if (isNaN(valor)) {
  return [{ json: { result: 'Erro: valor numérico não reconhecido. Use formato: comprimento 21.00' } }];
}

// Generate valid grid
const VALID_028 = [];
for (let v = 1.12; v <= 30; v = Math.round((v + 0.28) * 100) / 100) {
  VALID_028.push(Math.round(v * 100) / 100);
}

if (campo === 'altura') {
  if (valor < 2.0 || valor > 6.0) {
    const clamped = Math.min(6.0, Math.max(2.0, valor));
    const diff = Math.round((clamped - 2.0) * 100);
    const nearest = 2.0 + Math.round(diff / 5) * 0.05;
    return [{ json: { result: `altura ${valor}m: ❌ FORA DO RANGE (2.00-6.00m). Mais próximo válido: ${nearest.toFixed(2)}m` } }];
  }
  const diff = Math.round((valor - 2.0) * 100);
  if (diff % 5 === 0) {
    return [{ json: { result: `altura ${valor}m: ✅ VÁLIDO (múltiplo de 0.05m dentro de 2.00-6.00m)` } }];
  } else {
    const lower = 2.0 + Math.floor(diff / 5) * 0.05;
    const upper = lower + 0.05;
    const nearest = Math.abs(valor - lower) <= Math.abs(valor - upper) ? lower : upper;
    return [{ json: { result: `altura ${valor}m: ❌ NÃO VÁLIDO. Mais próximo: ${nearest.toFixed(2)}m (grade 0.05m)` } }];
  }
}

// Comprimento or Largura
const rounded = Math.round(valor * 100) / 100;
if (VALID_028.includes(rounded)) {
  return [{ json: { result: `${campo} ${valor}m: ✅ VÁLIDO — está na grade modular 0.28m` } }];
} else {
  let closest = VALID_028[0]; let minDiff = 999;
  for (const v of VALID_028) {
    const d = Math.abs(valor - v);
    if (d < minDiff) { minDiff = d; closest = v; }
  }
  // Also find the two surrounding values
  let lower = VALID_028[0], upper = VALID_028[VALID_028.length - 1];
  for (let i = 0; i < VALID_028.length - 1; i++) {
    if (VALID_028[i] <= valor && VALID_028[i+1] >= valor) {
      lower = VALID_028[i]; upper = VALID_028[i+1]; break;
    }
  }
  return [{ json: { result: `${campo} ${valor}m: ❌ NÃO MODULAR. Valores válidos vizinhos: ${lower.toFixed(2)}m e ${upper.toFixed(2)}m. Mais próximo: ${closest.toFixed(2)}m` } }];
}

